import React, { useEffect, useState } from "react";
import API from "../Api/axios";

const Home = ({ logout }) => {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    price: "",
    image: "",
    info: "",
  });

  const fetchProducts = async () => {
    try {
      const res = await API.get("/products");
      setProducts(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const [usersProducts, setUsersProducts] = useState([]);
  const [showUsersProducts, setShowUsersProducts] = useState(false);

  const fetchUsersProducts = async () => {
    try {
      const res = await API.get("/users/products/all");
      setUsersProducts(res.data);
      setShowUsersProducts(true);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to fetch users products");
    }
  };

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value,
    });
  };

  const addProduct = async (e) => {
    e.preventDefault();

    try {
      await API.post("/products/add", {
        name: form.name,
        price: Number(form.price),
        image: form.image,
        info: form.info,
      });

      setForm({
        name: "",
        price: "",
        image: "",
        info: "",
      });

      fetchProducts();
    } catch (err) {
      alert(err.response?.data?.message);
    }
  };

  const deleteProduct = async (id) => {
    try {
      await API.delete(`/products/${id}`);
      fetchProducts();
    } catch (err) {
      alert(err.response?.data?.message);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Product Dashboard</h2>

      <button onClick={logout}>Logout</button>

      <form onSubmit={addProduct}>
        <br />

        <input
          type="text"
          name="name"
          placeholder="Product Name"
          value={form.name}
          onChange={handleChange}
        />

        <input
          type="number"
          name="price"
          placeholder="Price"
          value={form.price}
          onChange={handleChange}
        />

        <input
          type="text"
          name="image"
          placeholder="Image URL"
          value={form.image}
          onChange={handleChange}
        />

        <textarea
          name="info"
          placeholder="Product information"
          value={form.info}
          onChange={handleChange}
        />

        <button type="submit">Add Product</button>
      </form>

      <hr />

      <div style={{ marginTop: 20 }}>
        <button onClick={fetchUsersProducts}>
          View Users' Products (Admin)
        </button>

        {showUsersProducts && (
          <div style={{ marginTop: 12 }}>
            {usersProducts.map((u) => (
              <div key={u.id} style={{ borderBottom: "1px solid #eee", padding: 8 }}>
                <strong>{u.name}</strong> ({u.email}) - {u.count} products

                <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
                  {u.products.map((p) => (
                    <div key={p._id} style={{ width: 140, border: "1px solid #ddd", padding: 6 }}>
                      {p.image && <img src={p.image} alt={p.name} style={{ width: "100%", height: 80, objectFit: "cover" }} />}
                      <div style={{ fontSize: 13 }}>{p.name}</div>
                      <div style={{ fontSize: 12 }}>₹{p.price}</div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {products.map((product) => (
        <div key={product._id}>
          <h4>
            {product.name} - ₹{product.price}
          </h4>

          {product.image && (
            <div>
              <img src={product.image} alt={product.name} style={{ width: 120 }} />
            </div>
          )}

          {product.info && <p>{product.info}</p>}

          <button
            onClick={() =>
              deleteProduct(product._id)
            }
          >
            Delete
          </button>
        </div>
      ))}
    </div>
  );
};

export default Home;
